<template>
  <div>
    <h1>Example</h1>
    <input type="button" id="" value="test" @click="onDeviceReady()" />
    <p>Read File</p>
  </div>
</template>

<script>
export default {
  name: "fileReader", // ่ฟไธชๅๅญๆจ่๏ผๅคงๅๅญๆฏๅผๅคด้ฉผๅณฐๆณๅฝๅใ
  props: {},
  components: {},
  directives: {},
  mixins: [],
  data() {
    return {
      dataProps: "",
    };
  },
  computed: {},
  created() {},
  mounted() {
    document.addEventListener("deviceready", this.onDeviceReady, false);
  },
  activated() {},
  destroyed() {
    document.removeEventListener("deviceready", this.onDeviceReady, false);
  },
  watch: {},
  methods: {
    onDeviceReady() {
      alert("0");
      window.requestFileSystem(
        LocalFileSystem.PERSISTENT,
        0,
        this.gotFS,
        this.fail
      );
    },

    gotFS(fileSystem) {
      alert("1");
      fileSystem.root.getFile("readme.txt", null, this.gotFileEntry, this.fail);
    },

    gotFileEntry(fileEntry) {
      alert("2");
      fileEntry.file(this.gotFile, this.fail);
    },

    gotFile(file) {
      alert("3");
      this.readDataUrl(file);
      this.readAsText(file);
    },

    readDataUrl(file) {
      alert("4");
      var reader = new FileReader();
      reader.onloadend = function (evt) {
        console.log("Read as data URL");
        console.log(evt.target.result);
      };
      reader.readAsDataURL(file);
    },

    readAsText(file) {
      alert("41");
      var reader = new FileReader();
      reader.onloadend = function (evt) {
        console.log("Read as text");
        alert("42" + evt.target.result);
        console.log(evt.target.result);
      };
      alert("5");
      reader.readAsText(file);
    },

    fail(evt) {
      alert("42");
      alert(evt.target.error.code);
      console.log(evt.target.error.code);
    },

    //๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝAndroidฦฝฬจ๏ฟฝฯบ๏ฟฝ๏ฟฝ๏ฟฝIOSฦฝฬจ๏ฟฝฯด๏ฟฝ๏ฟฝฤผ๏ฟฝึด๏ฟฝะตฤฒ๏ฟฝาป๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝ฿ผ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝหพ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝฦฝฬจ๏ฟฝะถ๏ฟฝ
    //IOS:๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝฦฌ๏ฟฝโฃฌ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝฤผ๏ฟฝ
    //Android:๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝิผ๏ฟฝะด๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝอจ๏ฟฝ๏ฟฝ๏ฟฝิผ๏ฟฝะด๏ฟฝฤฒ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝิผ๏ฟฝะด๏ฟฝ๏ฟฝิญ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝฤผ๏ฟฝ๏ฟฝ๏ฟฝาป๏ฟฝ๏ฟฝActivity๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝฤผ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝึธ๏ฟฝ๏ฟฝยท๏ฟฝ๏ฟฝ
    executeOpenFile() {
      console.log(" executeOpenFile()-->start");
      if (!ready) {
        console.log("Cordova is not ready,return");
        return;
      }

      resetloading();
      document.getElementById("contron").innerHTML = "๏ฟฝ๏ฟฝสผ";
      mam.navigator.dlfilebreakpointtransfer.pause(successCallback, null);

      function successCallback(msg) {}

      function errorCallback(msg) {}
      isstart = false;

      //๏ฟฝ๏ฟฝ๏ฟฝฤผ๏ฟฝสฑ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝะต๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝ
      document.getElementById("isok").innerHTML = "";
      //๏ฟฝ๏ฟฝศก๏ฟฝ่ฑธฦฝฬจ
      var devicePlatform = device.platform;
      console.log(" executeOpenFile() ,devicePlatform:" + devicePlatform);
      if ("iOS" == devicePlatform) {
        this.executeOpenFileByIOS();
      } else if ("Android" == devicePlatform) {
        this.executeOpenFileByAndroid();
      } else {
        console.log("invaiate platform");
      }
    },

    //ฮชAndroidฦฝฬจสฑ๏ฟฝ๏ฟฝ๏ฟฝฤผ๏ฟฝึด๏ฟฝะตฤฒ๏ฟฝ๏ฟฝ๏ฟฝ[๏ฟฝิผ๏ฟฝะด๏ฟฝฤฒ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝิผ๏ฟฝะด๏ฟฝฤฑ๏ฟฝ๏ฟฝ๏ฟฝำฆ๏ฟฝรด๏ฟฝำฆ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝสพฯตอณ๏ฟฝฤผ๏ฟฝ๏ฟฝ๏ฟฝฯข๏ฟฝ๏ฟฝ๏ฟฝรป๏ฟฝัก๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝฤผ๏ฟฝ๏ฟฝ๏ฟฝฯข]
    executeOpenFileByAndroid() {
      console.log("executeOpenFileByAndroid()-->start");
      mam.navigator.forward.goToFileExplorer(
        successCallback,
        null,
        DLForwardConstants.FileExplorer.ACTION_BREAK_POINT_FILE_UPLOAD
      );
      function successCallback(filePath) {
        console.log("successCallback() filePath:" + filePath);
        document.getElementById("file").value = filePath;
      }

      function errorCallback(msg) {
        console.log("errorCallback() msg:" + msg);
      }
    },

    //ฮชIOSฦฝฬจสฑ๏ฟฝ๏ฟฝึด๏ฟฝะด๏ฟฝ๏ฟฝฤผ๏ฟฝสฑ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝ
    executeOpenFileByIOS() {
      console.log("executeOpenFileByIOS()-->start");
      mam.navigator.camera.getPicture(uploadPhoto, errorCallback, {
        quality: 50,
        destinationType: mam.navigator.camera.DestinationType.FILE_URI,
        sourceType: mam.navigator.camera.PictureSourceType.PHOTOLIBRARY,
      });
      function uploadPhoto(filePath) {
        console.log("successCallback() filePath:" + filePath);
        document.getElementById("file").value = filePath;
      }

      function errorCallback(msg) {
        console.log("errorCallback() msg:" + msg);
      }
    },
  },
};
</script>
